<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">        &quot;private_metafield_namespaces&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: []</span></span>
